CREATE DATABASE CUSTOMER_BEHAVIOUR

Select * from customer 

--What is the total revenue generated by male vs female customers?
SELECT GENDER,SUM(PURCHASE_AMOUNT) AS TOTAL_REVENUE
FROM CUSTOMER
GROUP BY GENDER

--Which customers used a discount but still spent more than the average purchase amount 
SELECT CUSTOMER_ID,PURCHASE_AMOUNT FROM CUSTOMER
WHERE DISCOUNT_APPLIED = 'YES' AND 
PURCHASE_AMOUNT > (
SELECT AVG(PURCHASE_AMOUNT) AS AVG_AMOUNT FROM CUSTOMER
)

--Which are the top 5 products with the highest average review rating

SELECT TOP 5 ITEM_PURCHASED,
       ROUND(AVG(REVIEW_RATING),2) AS AVG_RATING
FROM CUSTOMER
GROUP BY ITEM_PURCHASED
ORDER BY AVG_RATING DESC;
 
 --Compare the average purchase amounts between standard and express shipping
 SELECT SHIPPING_TYPE,AVG(PURCHASE_AMOUNT) AS AVG_AMOUNT
 FROM CUSTOMER
 WHERE SHIPPING_TYPE IN ('STANDARD' ,'EXPRESS')
 GROUP BY SHIPPING_TYPE

 --Do subscribed customers spend more?Compare average spend and total revenue b/w subscribers & non-subscribers
SELECT SUBSCRIPTION_STATUS,
COUNT(CUSTOMER_ID) AS TOTAL_CUSTOMERS,
ROUND(AVG(PURCHASE_AMOUNT),2)AS AVG_SPENT,
ROUND(SUM(PURCHASE_AMOUNT),2) AS TOTAL_REVENUE
FROM CUSTOMER
GROUP BY SUBSCRIPTION_STATUS
ORDER BY AVG_SPENT,TOTAL_REVENUE DESC;

--Which 5 products have the highest percentage of purchase with discounts applied
SELECT TOP 5 ITEM_PURCHASED,
ROUND(100 * SUM(CASE WHEN DISCOUNT_APPLIED = 'YES' THEN 1 ELSE 0 END)/COUNT(*),2) AS DISCOUNT_RATE
FROM CUSTOMER
GROUP BY ITEM_PURCHASED
ORDER BY DISCOUNT_RATE DESC;

--Segment customers into New,Returning,and loyal based on their total number of previous purchases,
--and show the count of each segment
WITH CUSTOMER_TYPE AS(
SELECT CUSTOMER_ID,PREVIOUS_PURCHASES,
CASE
    WHEN PREVIOUS_PURCHASES = 1 THEN 'NEW'
    WHEN PREVIOUS_PURCHASES BETWEEN 2 AND 10 THEN 'RETURNING'
    ELSE 'LOYAL'
    END AS CUSTOMER_SEGMENT
FROM CUSTOMER
)

SELECT CUSTOMER_SEGMENT,COUNT(*) AS 'NUMBER_OF_CUSTOMERS'
FROM CUSTOMER_TYPE
GROUP BY CUSTOMER_SEGMENT

--WHAT ARE THE TOP 3 MOST PURCHASED PRODUCTS WITHIN EACH CATEGORY
;WITH ITEM_COUNTS AS(
SELECT CATEGORY,ITEM_PURCHASED,
COUNT(CUSTOMER_ID) AS TOTAL_ORDERS,
ROW_NUMBER()OVER(PARTITION BY CATEGORY ORDER BY COUNT(CUSTOMER_ID) DESC)AS ITEM_RANK
FROM CUSTOMER
GROUP BY CATEGORY,ITEM_PURCHASED
)

SELECT ITEM_RANK,CATEGORY,ITEM_PURCHASED,TOTAL_ORDERS
FROM ITEM_COUNTS
WHERE ITEM_RANK <= 3;

--Are customers who are repeat buyers(more than 5 previous purchases) also likely to subscribe?
SELECT SUBSCRIPTION_STATUS,
COUNT(CUSTOMER_ID) AS REPEAT_BUYERS
FROM CUSTOMER
WHERE PREVIOUS_PURCHASES > 5
GROUP BY SUBSCRIPTION_STATUS 

--What is the revenue contribution of each age group
SELECT AGE_GROUP,
SUM(PURCHASE_AMOUNT) AS TOTAL_REVENUE
FROM CUSTOMER
GROUP BY AGE_GROUP
ORDER BY TOTAL_REVENUE DESC